  1→use std::collections::HashSet;
  2→
  3→use crossterm::event::{KeyCode, KeyEvent, KeyModifiers};
  4→use mementor_lib::model::{ContentBlock, MessageRole, TranscriptEntry, TranscriptMessage};
  5→use ratatui::Frame;
  6→use ratatui::prelude::*;
  7→use ratatui::widgets::{Block, Borders, List, ListItem, Paragraph};
  8→
  9→// ---------------------------------------------------------------------------
 10→// Public types
 11→// ---------------------------------------------------------------------------
 12→
 13→/// Actions returned by transcript view key handling.
 14→pub enum TranscriptAction {
 15→    None,
 16→    Back,
 17→    ScrollTo(usize),
 18→}
 19→
 20→/// Persistent state for the fullscreen transcript viewer.
 21→pub struct TranscriptViewState {
 22→    /// Current scroll position (line-based).
 23→    pub scroll_offset: usize,
 24→    /// Indices of expanded tool-call blocks.
 25→    pub expanded_tools: HashSet<usize>,
 26→    /// Whether the right-hand tool-index sidebar is visible.
 27→    pub show_sidebar: bool,
 28→    /// Active search text (set after pressing Enter in search mode).
 29→    pub search_query: Option<String>,
 30→    /// Line indices that match the current search query.
 31→    pub search_matches: Vec<usize>,
 32→    /// Index into `search_matches` for n/N cycling.
 33→    pub search_index: usize,
 34→    /// Whether `/` search-input mode is active.
 35→    pub search_input_active: bool,
 36→    /// Buffer for typing a search query.
 37→    pub search_input_buf: String,
 38→    /// Whether progress entries are rendered (default: hidden).
 39→    pub show_progress: bool,
 40→
 41→    // -- Internal bookkeeping (updated each render) --------------------------
 42→    /// Total rendered line count from the last `render()` call.
 43→    total_lines: usize,
 44→    /// Maps tool sequential-index to its rendered-line position.
 45→    tool_line_map: Vec<usize>,
 46→}
 47→
 48→impl Default for TranscriptViewState {
 49→    fn default() -> Self {
 50→        Self::new()
 51→    }
 52→}
 53→
 54→impl TranscriptViewState {
 55→    pub fn new() -> Self {
 56→        Self {
 57→            scroll_offset: 0,
 58→            expanded_tools: HashSet::new(),
 59→            show_sidebar: true,
 60→            search_query: None,
 61→            search_matches: Vec::new(),
 62→            search_index: 0,
 63→            search_input_active: false,
 64→            search_input_buf: String::new(),
 65→            show_progress: false,
 66→            total_lines: 0,
 67→            tool_line_map: Vec::new(),
 68→        }
 69→    }
 70→
 71→    pub fn reset(&mut self) {
 72→        self.scroll_offset = 0;
 73→        self.expanded_tools.clear();
 74→        self.show_sidebar = true;
 75→        self.search_query = None;
 76→        self.search_matches.clear();
 77→        self.search_index = 0;
 78→        self.search_input_active = false;
 79→        self.search_input_buf.clear();
 80→        self.show_progress = false;
 81→        self.total_lines = 0;
 82→        self.tool_line_map.clear();
 83→    }
 84→}
 85→
 86→// ---------------------------------------------------------------------------
 87→// Rendering
 88→// ---------------------------------------------------------------------------
 89→
 90→/// Render the fullscreen transcript view.
 91→pub fn render(
 92→    frame: &mut Frame,
 93→    area: Rect,
 94→    state: &mut TranscriptViewState,
 95→    entries: &[TranscriptEntry],
 96→) {
 97→    // Build all displayable lines from transcript entries.
 98→    let (lines, tools) = build_lines(entries, state);
 99→    state.total_lines = lines.len();
100→    state.tool_line_map = tools.iter().map(|t| t.line_index).collect();
101→
102→    // Recompute search matches against freshly-built lines.
103→    if let Some(query) = &state.search_query {
104→        state.search_matches = find_matches(&lines, query);
105→        if !state.search_matches.is_empty() {
106→            state.search_index = state.search_index.min(state.search_matches.len() - 1);
107→        }
108→    }
109→
110→    // Two-panel layout when sidebar is visible.
111→    let (transcript_area, sidebar_area) = if state.show_sidebar {
112→        let chunks = Layout::default()
113→            .direction(Direction::Horizontal)
114→            .constraints([Constraint::Percentage(75), Constraint::Percentage(25)])
115→            .split(area);
116→        (chunks[0], Some(chunks[1]))
117→    } else {
118→        (area, None)
119→    };
120→
121→    // Reserve a bottom row for search bar when relevant.
122→    let show_search_bar = state.search_input_active || state.search_query.is_some();
123→    let (content_area, search_area) = if show_search_bar {
124→        let chunks = Layout::default()
125→            .direction(Direction::Vertical)
126→            .constraints([Constraint::Min(1), Constraint::Length(1)])
127→            .split(transcript_area);
128→        (chunks[0], Some(chunks[1]))
129→    } else {
130→        (transcript_area, None)
131→    };
132→
133→    // The border takes 2 rows (top + bottom).
134→    let inner_height = content_area.height.saturating_sub(2) as usize;
135→
136→    // Handle empty transcript.
137→    if entries.is_empty() {
138→        let block = Block::default().borders(Borders::ALL).title(" Transcript ");
139→        let inner = block.inner(content_area);
140→        frame.render_widget(block, content_area);
141→        let p = Paragraph::new("No transcript data").style(Style::default().fg(Color::DarkGray));
142→        frame.render_widget(p, inner);
143→        if let Some(sa) = sidebar_area {
144→            render_sidebar(frame, sa, &[], state);
145→        }
146→        return;
147→    }
148→
149→    // Clamp scroll offset.
150→    let max_scroll = lines.len().saturating_sub(inner_height);
151→    state.scroll_offset = state.scroll_offset.min(max_scroll);
152→
153→    // Slice visible lines.
154→    let visible: Vec<Line<'_>> = lines
155→        .iter()
156→        .skip(state.scroll_offset)
157→        .take(inner_height)
158→        .cloned()
159→        .collect();
160→
161→    // Apply search highlights to visible slice.
162→    let visible = if state.search_query.is_some() {
163→        apply_search_highlights(
164→            visible,
165→            state.search_query.as_deref().unwrap_or_default(),
166→            &state.search_matches,
167→            state.search_index,
168→            state.scroll_offset,
169→        )
170→    } else {
171→        visible
172→    };
173→
174→    // Scroll position indicator.
175→    let scroll_info = {
176→        let end = (state.scroll_offset + inner_height).min(lines.len());
177→        format!(" {}-{}/{} ", state.scroll_offset + 1, end, lines.len())
178→    };
179→
180→    let progress_hint = if state.show_progress {
181→        " p:hide progress "
182→    } else {
183→        " p:show progress "
184→    };
185→
186→    let transcript_widget = Paragraph::new(Text::from(visible)).block(
187→        Block::default()
188→            .borders(Borders::ALL)
189→            .title(" Transcript ")
190→            .title_bottom(
191→                Line::from(vec![
192→                    Span::styled(progress_hint, Style::default().fg(Color::DarkGray)),
193→                    Span::styled(scroll_info, Style::default()),
194→                ])
195→                .right_aligned(),
196→            ),
197→    );
198→    frame.render_widget(transcript_widget, content_area);
199→
200→    // Search bar.
201→    if let Some(search_area) = search_area {
202→        render_search_bar(frame, search_area, state);
203→    }
204→
205→    // Sidebar.
206→    if let Some(sidebar_area) = sidebar_area {
207→        render_sidebar(frame, sidebar_area, &tools, state);
208→    }
209→}
210→
211→// ---------------------------------------------------------------------------
212→// Key handling
213→// ---------------------------------------------------------------------------
214→
215→/// Handle key events for the transcript view.
216→pub fn handle_key(
217→    key: KeyEvent,
218→    state: &mut TranscriptViewState,
219→    _entry_count: usize,
220→) -> TranscriptAction {
221→    // Search input mode intercepts all keys.
222→    if state.search_input_active {
223→        return handle_search_input(key, state);
224→    }
225→
226→    match key.code {
227→        // -- Scrolling -------------------------------------------------------
228→        KeyCode::Char('j') | KeyCode::Down => {
229→            state.scroll_offset = state.scroll_offset.saturating_add(1);
230→            TranscriptAction::None
231→        }
232→        KeyCode::Char('k') | KeyCode::Up => {
233→            state.scroll_offset = state.scroll_offset.saturating_sub(1);
234→            TranscriptAction::None
235→        }
236→        KeyCode::Char('d') if key.modifiers.contains(KeyModifiers::CONTROL) => {
237→            state.scroll_offset = state.scroll_offset.saturating_add(20);
238→            TranscriptAction::None
239→        }
240→        KeyCode::Char('u') if key.modifiers.contains(KeyModifiers::CONTROL) => {
241→            state.scroll_offset = state.scroll_offset.saturating_sub(20);
242→            TranscriptAction::None
243→        }
244→        KeyCode::Char('g') => {
245→            state.scroll_offset = 0;
246→            TranscriptAction::None
247→        }
248→        KeyCode::Char('G') => {
249→            state.scroll_offset = state.total_lines;
250→            TranscriptAction::None
251→        }
252→
253→        // -- Tool expand / collapse ------------------------------------------
254→        KeyCode::Enter => {
255→            toggle_nearest_tool(state);
256→            TranscriptAction::None
257→        }
258→
259→        // -- Search ----------------------------------------------------------
260→        KeyCode::Char('/') => {
261→            state.search_input_active = true;
262→            state.search_input_buf.clear();
263→            TranscriptAction::None
264→        }
265→        KeyCode::Char('n') => {
266→            advance_match(state, true);
267→            TranscriptAction::None
268→        }
269→        KeyCode::Char('N') => {
270→            advance_match(state, false);
271→            TranscriptAction::None
272→        }
273→
274→        // -- Progress toggle -------------------------------------------------
275→        KeyCode::Char('p') => {
276→            state.show_progress = !state.show_progress;
277→            TranscriptAction::None
278→        }
279→
280→        // -- Sidebar ---------------------------------------------------------
281→        KeyCode::Char('o') => {
282→            state.show_sidebar = !state.show_sidebar;
283→            TranscriptAction::None
284→        }
285→
286→        // -- Back / Esc ------------------------------------------------------
287→        KeyCode::Esc => {
288→            if state.search_query.is_some() {
289→                // First Esc clears search; second Esc goes back.
290→                state.search_query = None;
291→                state.search_matches.clear();
292→                state.search_index = 0;
293→                TranscriptAction::None
294→            } else {
295→                TranscriptAction::Back
296→            }
297→        }
298→
299→        _ => TranscriptAction::None,
300→    }
301→}
302→
303→// ---------------------------------------------------------------------------
304→// Internal: line building
305→// ---------------------------------------------------------------------------
306→
307→/// Metadata for a tool-use block tracked during line building.
308→struct ToolEntry {
309→    name: String,
310→    line_index: usize,
311→    tool_index: usize,
312→}
313→
314→/// Convert transcript entries into a flat list of styled lines plus tool
315→/// metadata for the sidebar.
316→fn build_lines(
317→    entries: &[TranscriptEntry],
318→    state: &TranscriptViewState,
319→) -> (Vec<Line<'static>>, Vec<ToolEntry>) {
320→    let mut lines: Vec<Line<'static>> = Vec::new();
321→    let mut tools: Vec<ToolEntry> = Vec::new();
322→    let mut tool_seq: usize = 0;
323→
324→    for entry in entries {
325→        match entry {
326→            TranscriptEntry::Message(msg) => {
327→                append_message(msg, state, &mut lines, &mut tools, &mut tool_seq);
328→            }
329→            TranscriptEntry::FileHistorySnapshot { files } => {
330→                lines.push(Line::from(Span::styled(
331→                    format!("--- file snapshot ({} files) ---", files.len()),
332→                    Style::default().fg(Color::DarkGray),
333→                )));
334→                lines.push(Line::from(""));
335→            }
336→            TranscriptEntry::PrLink {
337→                pr_number, pr_url, ..
338→            } => {
339→                lines.push(Line::from(Span::styled(
340→                    format!("PR #{pr_number}: {pr_url}"),
341→                    Style::default().fg(Color::Cyan),
342→                )));
343→                lines.push(Line::from(""));
344→            }
345→            TranscriptEntry::Progress(raw) => {
346→                if state.show_progress {
347→                    let display = truncate(raw, 80);
348→                    lines.push(Line::from(Span::styled(
349→                        format!("[progress] {display}"),
350→                        Style::default().fg(Color::DarkGray),
351→                    )));
352→                }
353→            }
354→            TranscriptEntry::Other(_) => {}
355→        }
356→    }
357→
358→    (lines, tools)
359→}
360→
361→fn append_message(
362→    msg: &TranscriptMessage,
363→    state: &TranscriptViewState,
364→    lines: &mut Vec<Line<'static>>,
365→    tools: &mut Vec<ToolEntry>,
366→    tool_seq: &mut usize,
367→) {
368→    // Header line.
369→    let (style, label) = match msg.role {
370→        MessageRole::User => (
371→            Style::default()
372→                .fg(Color::Green)
373→                .add_modifier(Modifier::BOLD),
374→            "[User]",
375→        ),
376→        MessageRole::Assistant => (
377→            Style::default()
378→                .fg(Color::Blue)
379→                .add_modifier(Modifier::BOLD),
380→            "[Assistant]",
381→        ),
382→    };
383→    let ts = msg.timestamp.as_deref().unwrap_or("");
384→    lines.push(Line::from(vec![
385→        Span::styled(format!("{label} "), style),
386→        Span::styled(ts.to_owned(), Style::default().fg(Color::DarkGray)),
387→    ]));
388→
389→    // Content blocks.
390→    for block in &msg.content {
391→        match block {
392→            ContentBlock::Text(text) => {
393→                for l in text.lines() {
394→                    lines.push(Line::from(format!("  {l}")));
395→                }
396→                if text.is_empty() {
397→                    lines.push(Line::from(""));
398→                }
399→            }
400→            ContentBlock::Thinking(text) => {
401→                append_thinking(text, lines);
402→            }
403→            ContentBlock::ToolUse { name, input } => {
404→                append_tool_use(name, input, *tool_seq, state, lines, tools);
405→                *tool_seq += 1;
406→            }
407→            ContentBlock::ToolResult { content, .. } => {
408→                append_tool_result(content, tool_seq.saturating_sub(1), state, lines);
409→            }
410→        }
411→    }
412→
413→    // Blank separator after each message.
414→    lines.push(Line::from(""));
415→}
416→
417→fn append_thinking(text: &str, lines: &mut Vec<Line<'static>>) {
418→    let first = text.lines().next().unwrap_or("");
419→    let multi = text.lines().count() > 1;
420→    let preview = if first.chars().count() > 60 {
421→        format!("{}...", first.chars().take(60).collect::<String>())
422→    } else if multi {
423→        format!("{first}...")
424→    } else {
425→        first.to_owned()
426→    };
427→    lines.push(Line::from(Span::styled(
428→        format!("  [thinking] {preview}"),
429→        Style::default()
430→            .fg(Color::DarkGray)
431→            .add_modifier(Modifier::ITALIC),
432→    )));
433→}
434→
435→fn append_tool_use(
436→    name: &str,
437→    input: &impl std::fmt::Display,
438→    idx: usize,
439→    state: &TranscriptViewState,
440→    lines: &mut Vec<Line<'static>>,
441→    tools: &mut Vec<ToolEntry>,
442→) {
443→    tools.push(ToolEntry {
444→        name: name.to_owned(),
445→        line_index: lines.len(),
446→        tool_index: idx,
447→    });
448→
449→    let expanded = state.expanded_tools.contains(&idx);
450→
451→    if expanded {
452→        // Top border with tool name.
453→        lines.push(Line::from(vec![
454→            Span::styled("  \u{250c}\u{2500} ", Style::default().fg(Color::Yellow)),
455→            Span::styled(
456→                format!("[{idx}] {name}"),
457→                Style::default()
458→                    .fg(Color::Yellow)
459→                    .add_modifier(Modifier::BOLD),
460→            ),
461→        ]));
462→        // Args (compact JSON, split into wrapped chunks).
463→        let raw = input.to_string();
464→        for chunk in wrap_str(&raw, 100) {
465→            lines.push(Line::from(Span::styled(
466→                format!("  \u{2502} {chunk}"),
467→                Style::default().fg(Color::Yellow),
468→            )));
469→        }
470→        // Bottom border.
471→        lines.push(Line::from(Span::styled(
472→            "  \u{2514}\u{2500}".to_owned(),
473→            Style::default().fg(Color::Yellow),
474→        )));
475→    } else {
476→        // Collapsed: single line with tool name and truncated args.
477→        let preview = truncate(&input.to_string(), 60);
478→        lines.push(Line::from(vec![
479→            Span::styled(format!("  [{idx}] "), Style::default().fg(Color::Yellow)),
480→            Span::styled(
481→                name.to_owned(),
482→                Style::default()
483→                    .fg(Color::Yellow)
484→                    .add_modifier(Modifier::BOLD),
485→            ),
486→            Span::styled(format!(" {preview}"), Style::default().fg(Color::DarkGray)),
487→        ]));
488→    }
489→}
490→
491→fn append_tool_result(
492→    content: &str,
493→    parent_idx: usize,
494→    state: &TranscriptViewState,
495→    lines: &mut Vec<Line<'static>>,
496→) {
497→    // Only show result when the parent tool is expanded.
498→    if !state.expanded_tools.contains(&parent_idx) {
499→        return;
500→    }
501→    lines.push(Line::from(Span::styled(
502→        "  Result:".to_owned(),
503→        Style::default()
504→            .fg(Color::DarkGray)
505→            .add_modifier(Modifier::BOLD),
506→    )));
507→    for l in content.lines().take(15) {
508→        lines.push(Line::from(Span::styled(
509→            format!("    {l}"),
510→            Style::default().fg(Color::DarkGray),
511→        )));
512→    }
513→    if content.lines().count() > 15 {
514→        lines.push(Line::from(Span::styled(
515→            "    ...".to_owned(),
516→            Style::default().fg(Color::DarkGray),
517→        )));
518→    }
519→}
520→
521→// ---------------------------------------------------------------------------
522→// Internal: sidebar
523→// ---------------------------------------------------------------------------
524→
525→fn render_sidebar(frame: &mut Frame, area: Rect, tools: &[ToolEntry], state: &TranscriptViewState) {
526→    let nearest = nearest_tool_index(state);
527→
528→    let items: Vec<ListItem<'_>> = tools
529→        .iter()
530→        .map(|t| {
531→            let is_current = nearest == Some(t.tool_index);
532→            let is_expanded = state.expanded_tools.contains(&t.tool_index);
533→
534→            let style = if is_current {
535→                Style::default()
536→                    .fg(Color::Yellow)
537→                    .add_modifier(Modifier::BOLD)
538→            } else if is_expanded {
539→                Style::default().fg(Color::Yellow)
540→            } else {
541→                Style::default().fg(Color::DarkGray)
542→            };
543→
544→            let marker = if is_expanded { "\u{25bc}" } else { "\u{25b6}" };
545→            ListItem::new(Line::from(Span::styled(
546→                format!("{marker} [{0}] {1}", t.tool_index, t.name),
547→                style,
548→            )))
549→        })
550→        .collect();
551→
552→    let list = List::new(items).block(Block::default().borders(Borders::ALL).title(" Tools "));
553→    frame.render_widget(list, area);
554→}
555→
556→// ---------------------------------------------------------------------------
557→// Internal: search bar
558→// ---------------------------------------------------------------------------
559→
560→fn render_search_bar(frame: &mut Frame, area: Rect, state: &TranscriptViewState) {
561→    let text = if state.search_input_active {
562→        format!("/{}", state.search_input_buf)
563→    } else if let Some(q) = &state.search_query {
564→        let info = if state.search_matches.is_empty() {
565→            "no matches".to_owned()
566→        } else {
567→            format!("{}/{}", state.search_index + 1, state.search_matches.len())
568→        };
569→        format!("/{q}  [{info}]")
570→    } else {
571→        String::new()
572→    };
573→
574→    let bar = Paragraph::new(text).style(Style::default().fg(Color::Yellow));
575→    frame.render_widget(bar, area);
576→}
577→
578→// ---------------------------------------------------------------------------
579→// Internal: search helpers
580→// ---------------------------------------------------------------------------
581→
582→fn find_matches(lines: &[Line<'_>], query: &str) -> Vec<usize> {
583→    let q = query.to_ascii_lowercase();
584→    lines
585→        .iter()
586→        .enumerate()
587→        .filter(|(_, line)| {
588→            let text: String = line.spans.iter().map(|s| s.content.as_ref()).collect();
589→            text.to_ascii_lowercase().contains(&q)
590→        })
591→        .map(|(i, _)| i)
592→        .collect()
593→}
594→
595→fn apply_search_highlights<'a>(
596→    lines: Vec<Line<'a>>,
597→    query: &str,
598→    matches: &[usize],
599→    current_idx: usize,
600→    scroll_offset: usize,
601→) -> Vec<Line<'a>> {
602→    let current_line = matches.get(current_idx).copied();
603→    let query_lower = query.to_ascii_lowercase();
604→    let qlen = query.len();
605→
606→    lines
607→        .into_iter()
608→        .enumerate()
609→        .map(|(i, line)| {
610→            let abs = scroll_offset + i;
611→            if !matches.contains(&abs) {
612→                return line;
613→            }
614→            let bg = if current_line == Some(abs) {
615→                Color::Yellow
616→            } else {
617→                Color::DarkGray
618→            };
619→            let new_spans: Vec<Span<'a>> = line
620→                .spans
621→                .into_iter()
622→                .flat_map(|span| highlight_span(span, &query_lower, qlen, bg))
623→                .collect();
624→            Line::from(new_spans)
625→        })
626→        .collect()
627→}
628→
629→fn highlight_span<'a>(span: Span<'a>, query_lower: &str, qlen: usize, bg: Color) -> Vec<Span<'a>> {
630→    let text = span.content.to_string();
631→    let text_lower = text.to_ascii_lowercase();
632→    let positions: Vec<usize> = text_lower
633→        .match_indices(query_lower)
634→        .map(|(pos, _)| pos)
635→        .collect();
636→
637→    if positions.is_empty() {
638→        return vec![span];
639→    }
640→
641→    let base_style = span.style;
642→    let hl_style = base_style.bg(bg).fg(Color::Black);
643→    let mut out = Vec::new();
644→    let mut cursor = 0;
645→
646→    for pos in positions {
647→        if pos > cursor {
648→            out.push(Span::styled(text[cursor..pos].to_owned(), base_style));
649→        }
650→        let end = (pos + qlen).min(text.len());
651→        out.push(Span::styled(text[pos..end].to_owned(), hl_style));
652→        cursor = end;
653→    }
654→    if cursor < text.len() {
655→        out.push(Span::styled(text[cursor..].to_owned(), base_style));
656→    }
657→    out
658→}
659→
660→fn handle_search_input(key: KeyEvent, state: &mut TranscriptViewState) -> TranscriptAction {
661→    match key.code {
662→        KeyCode::Enter => {
663→            if state.search_input_buf.is_empty() {
664→                state.search_query = None;
665→                state.search_matches.clear();
666→            } else {
667→                state.search_query = Some(state.search_input_buf.clone());
668→            }
669→            state.search_input_active = false;
670→            state.search_index = 0;
671→            TranscriptAction::None
672→        }
673→        KeyCode::Esc => {
674→            state.search_input_active = false;
675→            state.search_input_buf.clear();
676→            TranscriptAction::None
677→        }
678→        KeyCode::Backspace => {
679→            state.search_input_buf.pop();
680→            TranscriptAction::None
681→        }
682→        KeyCode::Char(c) => {
683→            state.search_input_buf.push(c);
684→            TranscriptAction::None
685→        }
686→        _ => TranscriptAction::None,
687→    }
688→}
689→
690→fn advance_match(state: &mut TranscriptViewState, forward: bool) {
691→    if state.search_matches.is_empty() {
692→        return;
693→    }
694→    let len = state.search_matches.len();
695→    state.search_index = if forward {
696→        (state.search_index + 1) % len
697→    } else if state.search_index == 0 {
698→        len - 1
699→    } else {
700→        state.search_index - 1
701→    };
702→    if let Some(&line) = state.search_matches.get(state.search_index) {
703→        state.scroll_offset = line;
704→    }
705→}
706→
707→// ---------------------------------------------------------------------------
708→// Internal: tool toggle
709→// ---------------------------------------------------------------------------
710→
711→fn nearest_tool_index(state: &TranscriptViewState) -> Option<usize> {
712→    let scroll = state.scroll_offset;
713→    let mut best: Option<(usize, usize)> = None;
714→    for (idx, &line_pos) in state.tool_line_map.iter().enumerate() {
715→        let dist = scroll.abs_diff(line_pos);
716→        if dist <= 5 && best.is_none_or(|(_, d)| dist < d) {
717→            best = Some((idx, dist));
718→        }
719→    }
720→    best.map(|(idx, _)| idx)
721→}
722→
723→fn toggle_nearest_tool(state: &mut TranscriptViewState) {
724→    if let Some(idx) = nearest_tool_index(state) {
725→        if state.expanded_tools.contains(&idx) {
726→            state.expanded_tools.remove(&idx);
727→        } else {
728→            state.expanded_tools.insert(idx);
729→        }
730→    }
731→}
732→
733→// ---------------------------------------------------------------------------
734→// Internal: text utilities
735→// ---------------------------------------------------------------------------
736→
737→fn truncate(s: &str, max_width: usize) -> String {
738→    super::text_utils::truncate(s, max_width)
739→}
740→
741→fn wrap_str(s: &str, width: usize) -> Vec<String> {
742→    super::text_utils::wrap_str(s, width)
743→}
