  1→use std::collections::HashMap;
  2→use std::io::Stdout;
  3→
  4→use anyhow::Result;
  5→use crossterm::event::{self, Event, KeyCode, KeyEvent, KeyModifiers};
  6→use crossterm::execute;
  7→use crossterm::terminal::{self, EnterAlternateScreen, LeaveAlternateScreen};
  8→use mementor_lib::cache::DataCache;
  9→use mementor_lib::git::branch::list_branches;
 10→use mementor_lib::git::diff::FileStatus;
 11→use mementor_lib::model::{CheckpointMeta, TranscriptEntry};
 12→use ratatui::Terminal;
 13→use ratatui::backend::CrosstermBackend;
 14→use ratatui::prelude::*;
 15→use ratatui::widgets::ListState;
 16→
 17→use crate::views::{branch_popup, dashboard, detail, diff_view, git_log, status_bar, transcript};
 18→
 19→/// The active view in the application.
 20→pub enum View {
 21→    CheckpointList,
 22→    /// Checkpoint detail — carries the checkpoint index into `cache.checkpoints()`.
 23→    CheckpointDetail(usize),
 24→    /// Fullscreen transcript — checkpoint index + session index.
 25→    Transcript {
 26→        checkpoint_idx: usize,
 27→        session_idx: usize,
 28→    },
 29→    /// Diff view — commit hash.
 30→    DiffView(String),
 31→    /// Git log.
 32→    GitLog,
 33→}
 34→
 35→pub struct App {
 36→    pub view: View,
 37→    pub cache: DataCache,
 38→    pub list_state: ListState,
 39→    pub selected_branch: String,
 40→    pub running: bool,
 41→    pub branch_popup_open: bool,
 42→    pub branches: Vec<String>,
 43→    pub branch_list_state: ListState,
 44→
 45→    // Per-view state.
 46→    pub detail_state: detail::DetailState,
 47→    pub transcript_state: transcript::TranscriptViewState,
 48→    pub diff_state: diff_view::DiffViewState,
 49→    pub git_log_state: git_log::GitLogState,
 50→
 51→    /// Cached transcript entries for the currently viewed checkpoint session.
 52→    pub loaded_transcript: Option<Vec<TranscriptEntry>>,
 53→}
 54→
 55→impl App {
 56→    pub fn new(cache: DataCache, branch: String) -> Self {
 57→        let mut list_state = ListState::default();
 58→        if !cache.checkpoints().is_empty() {
 59→            list_state.select(Some(0));
 60→        }
 61→        Self {
 62→            view: View::CheckpointList,
 63→            cache,
 64→            list_state,
 65→            selected_branch: branch,
 66→            running: true,
 67→            branch_popup_open: false,
 68→            branches: Vec::new(),
 69→            branch_list_state: ListState::default(),
 70→            detail_state: detail::DetailState::new(0),
 71→            transcript_state: transcript::TranscriptViewState::new(),
 72→            diff_state: diff_view::DiffViewState::new(),
 73→            git_log_state: git_log::GitLogState::new(),
 74→            loaded_transcript: None,
 75→        }
 76→    }
 77→
 78→    pub fn setup_terminal() -> Result<Terminal<CrosstermBackend<Stdout>>> {
 79→        terminal::enable_raw_mode()?;
 80→        let mut stdout = std::io::stdout();
 81→        execute!(stdout, EnterAlternateScreen)?;
 82→        let backend = CrosstermBackend::new(stdout);
 83→        let terminal = Terminal::new(backend)?;
 84→        Ok(terminal)
 85→    }
 86→
 87→    pub fn restore_terminal(terminal: &mut Terminal<CrosstermBackend<Stdout>>) -> Result<()> {
 88→        terminal::disable_raw_mode()?;
 89→        execute!(terminal.backend_mut(), LeaveAlternateScreen)?;
 90→        terminal.show_cursor()?;
 91→        Ok(())
 92→    }
 93→
 94→    pub async fn run(&mut self, terminal: &mut Terminal<CrosstermBackend<Stdout>>) -> Result<()> {
 95→        loop {
 96→            terminal.draw(|frame| self.render(frame))?;
 97→
 98→            if event::poll(std::time::Duration::from_millis(100))?
 99→                && let Event::Key(key) = event::read()?
100→            {
101→                self.handle_key(key).await;
102→            }
103→
104→            if !self.running {
105→                break;
106→            }
107→        }
108→        Ok(())
109→    }
110→
111→    fn render(&mut self, frame: &mut Frame) {
112→        let area = frame.area();
113→
114→        let chunks = Layout::default()
115→            .direction(Direction::Vertical)
116→            .constraints([Constraint::Min(1), Constraint::Length(1)])
117→            .split(area);
118→
119→        match &self.view {
120→            View::CheckpointList => dashboard::render(frame, chunks[0], self),
121→            View::CheckpointDetail(idx) => {
122→                let idx = *idx;
123→                let checkpoints = self.cache.checkpoints();
124→                if let Some(cp) = checkpoints.get(idx) {
125→                    let cp = cp.clone();
126→                    let commits = self.cache.commits().to_vec();
127→                    let transcript_ref = self.loaded_transcript.as_deref();
128→                    let file_statuses = build_file_statuses(&self.cache, &cp);
129→                    detail::render(
130→                        frame,
131→                        chunks[0],
132→                        &mut self.detail_state,
133→                        &cp,
134→                        &commits,
135→                        &file_statuses,
136→                        transcript_ref,
137→                    );
138→                }
139→            }
140→            View::Transcript { .. } => {
141→                let entries = self.loaded_transcript.as_deref().unwrap_or(&[]);
142→                transcript::render(frame, chunks[0], &mut self.transcript_state, entries);
143→            }
144→            View::DiffView(hash) => {
145→                let header = hash.clone();
146→                let diffs = self
147→                    .cache
148→                    .cached_diffs(&header)
149→                    .map(<[mementor_lib::git::diff::FileDiff]>::to_vec)
150→                    .unwrap_or_default();
151→                diff_view::render(frame, chunks[0], &mut self.diff_state, &diffs, &header);
152→            }
153→            View::GitLog => {
154→                let commits = self.cache.commits().to_vec();
155→                git_log::render(frame, chunks[0], &mut self.git_log_state, &commits);
156→            }
157→        }
158→        status_bar::render(frame, chunks[1], self);
159→
160→        if self.branch_popup_open {
161→            branch_popup::render(frame, area, self);
162→        }
163→    }
164→
165→    async fn handle_key(&mut self, key: KeyEvent) {
166→        // Ctrl-c always quits.
167→        if key.modifiers.contains(KeyModifiers::CONTROL) && key.code == KeyCode::Char('c') {
168→            self.running = false;
169→            return;
170→        }
171→
172→        if self.branch_popup_open {
173→            branch_popup::handle_key(key, self).await;
174→            return;
175→        }
176→
177→        match &self.view {
178→            View::CheckpointList => self.handle_dashboard_key(key).await,
179→            View::CheckpointDetail(idx) => {
180→                let idx = *idx;
181→                self.handle_detail_key(key, idx).await;
182→            }
183→            View::Transcript {
184→                checkpoint_idx,
185→                session_idx,
186→            } => {
187→                let cp_idx = *checkpoint_idx;
188→                let s_idx = *session_idx;
189→                self.handle_transcript_key(key, cp_idx, s_idx);
190→            }
191→            View::DiffView(hash) => {
192→                let hash = hash.clone();
193→                self.handle_diff_key(key, &hash);
194→            }
195→            View::GitLog => self.handle_git_log_key(key).await,
196→        }
197→    }
198→
199→    async fn handle_dashboard_key(&mut self, key: KeyEvent) {
200→        match key.code {
201→            KeyCode::Char('q') => self.running = false,
202→            KeyCode::Char('j') | KeyCode::Down => self.select_next(),
203→            KeyCode::Char('k') | KeyCode::Up => self.select_prev(),
204→            KeyCode::Char('b') => self.open_branch_popup().await,
205→            KeyCode::Char('r') => {
206→                let _ = self.cache.refresh().await;
207→                self.clamp_selection();
208→            }
209→            KeyCode::Char('g') => {
210→                self.git_log_state.reset(self.cache.commits().len());
211→                self.view = View::GitLog;
212→            }
213→            KeyCode::Enter => {
214→                if let Some(idx) = self.list_state.selected() {
215→                    self.open_detail(idx).await;
216→                }
217→            }
218→            _ => {}
219→        }
220→    }
221→
222→    async fn handle_detail_key(&mut self, key: KeyEvent, checkpoint_idx: usize) {
223→        let checkpoints = self.cache.checkpoints();
224→        let Some(cp) = checkpoints.get(checkpoint_idx).cloned() else {
225→            self.view = View::CheckpointList;
226→            return;
227→        };
228→        let commits = self.cache.commits().to_vec();
229→
230→        let action = detail::handle_key(key, &mut self.detail_state, &cp, &commits);
231→        match action {
232→            detail::DetailAction::Back => {
233→                self.view = View::CheckpointList;
234→                self.loaded_transcript = None;
235→            }
236→            detail::DetailAction::OpenTranscript { session_idx } => {
237→                self.transcript_state.reset();
238→                self.view = View::Transcript {
239→                    checkpoint_idx,
240→                    session_idx,
241→                };
242→                // Load transcript if not already loaded for this session.
243→                self.load_transcript_for_session(&cp, session_idx).await;
244→            }
245→            detail::DetailAction::OpenDiff { commit_hash } => {
246→                self.open_diff(&commit_hash).await;
247→            }
248→            detail::DetailAction::OpenGitLog => {
249→                self.git_log_state.reset(self.cache.commits().len());
250→                self.view = View::GitLog;
251→            }
252→            detail::DetailAction::None => {}
253→        }
254→    }
255→
256→    fn handle_transcript_key(&mut self, key: KeyEvent, checkpoint_idx: usize, _session_idx: usize) {
257→        let entries = self.loaded_transcript.as_deref().unwrap_or(&[]);
258→        let action = transcript::handle_key(key, &mut self.transcript_state, entries.len());
259→        match action {
260→            transcript::TranscriptAction::Back => {
261→                self.view = View::CheckpointDetail(checkpoint_idx);
262→            }
263→            transcript::TranscriptAction::None | transcript::TranscriptAction::ScrollTo(_) => {}
264→        }
265→    }
266→
267→    fn handle_diff_key(&mut self, key: KeyEvent, hash: &str) {
268→        let diffs = self
269→            .cache
270→            .cached_diffs(hash)
271→            .map(<[mementor_lib::git::diff::FileDiff]>::to_vec)
272→            .unwrap_or_default();
273→        let action = diff_view::handle_key(key, &mut self.diff_state, &diffs);
274→        match action {
275→            diff_view::DiffViewAction::Back => {
276→                // Go back to wherever we came from. For simplicity, go to
277→                // checkpoint list. A proper back-stack could be added later.
278→                self.view = View::CheckpointList;
279→            }
280→            diff_view::DiffViewAction::None => {}
281→        }
282→    }
283→
284→    async fn handle_git_log_key(&mut self, key: KeyEvent) {
285→        let commits = self.cache.commits().to_vec();
286→        let action = git_log::handle_key(key, &mut self.git_log_state, &commits);
287→        match action {
288→            git_log::GitLogAction::Back => {
289→                self.view = View::CheckpointList;
290→            }
291→            git_log::GitLogAction::OpenCheckpoint(cp_id) => {
292→                // Find checkpoint index by checkpoint_id.
293→                if let Some(idx) = self
294→                    .cache
295→                    .checkpoints()
296→                    .iter()
297→                    .position(|c| c.checkpoint_id == cp_id)
298→                {
299→                    self.open_detail(idx).await;
300→                }
301→            }
302→            git_log::GitLogAction::OpenDiff(hash) => {
303→                self.open_diff(&hash).await;
304→            }
305→            git_log::GitLogAction::None => {}
306→        }
307→    }
308→
309→    async fn open_detail(&mut self, checkpoint_idx: usize) {
310→        let session_count = self
311→            .cache
312→            .checkpoints()
313→            .get(checkpoint_idx)
314→            .map_or(0, |cp| cp.sessions.len());
315→        self.detail_state.reset(session_count);
316→        self.view = View::CheckpointDetail(checkpoint_idx);
317→
318→        // Eagerly load transcript for the first session.
319→        if let Some(cp) = self.cache.checkpoints().get(checkpoint_idx).cloned() {
320→            self.load_transcript_for_session(&cp, 0).await;
321→        }
322→    }
323→
324→    async fn open_diff(&mut self, commit_hash: &str) {
325→        // Pre-load diffs.
326→        let _ = self.cache.diffs(commit_hash).await;
327→        self.diff_state.reset();
328→        self.view = View::DiffView(commit_hash.to_owned());
329→    }
330→
331→    async fn load_transcript_for_session(
332→        &mut self,
333→        cp: &mementor_lib::model::CheckpointMeta,
334→        session_idx: usize,
335→    ) {
336→        if let Some(session) = cp.sessions.get(session_idx)
337→            && !session.blob_path.is_empty()
338→            && let Ok(entries) = self.cache.transcript(&session.blob_path).await
339→        {
340→            self.loaded_transcript = Some(entries.to_vec());
341→            return;
342→        }
343→        self.loaded_transcript = None;
344→    }
345→
346→    fn select_next(&mut self) {
347→        let len = self.cache.checkpoints().len();
348→        if len == 0 {
349→            return;
350→        }
351→        let i = self
352→            .list_state
353→            .selected()
354→            .map_or(0, |i| if i + 1 < len { i + 1 } else { i });
355→        self.list_state.select(Some(i));
356→    }
357→
358→    fn select_prev(&mut self) {
359→        let len = self.cache.checkpoints().len();
360→        if len == 0 {
361→            return;
362→        }
363→        let i = self
364→            .list_state
365→            .selected()
366→            .map_or(0, |i| i.saturating_sub(1));
367→        self.list_state.select(Some(i));
368→    }
369→
370→    pub(crate) fn clamp_selection(&mut self) {
371→        let len = self.cache.checkpoints().len();
372→        if len == 0 {
373→            self.list_state.select(None);
374→        } else if let Some(i) = self.list_state.selected()
375→            && i >= len
376→        {
377→            self.list_state.select(Some(len - 1));
378→        }
379→    }
380→
381→    async fn open_branch_popup(&mut self) {
382→        self.branches = list_branches().await.unwrap_or_default();
383→        let selected_index = self
384→            .branches
385→            .iter()
386→            .position(|b| b == &self.selected_branch)
387→            .unwrap_or(0);
388→        self.branch_list_state.select(Some(selected_index));
389→        self.branch_popup_open = true;
390→    }
391→}
392→
393→/// Build a map of file path → `FileStatus` from cached diffs for the
394→/// checkpoint's commit hashes.
395→fn build_file_statuses(
396→    cache: &DataCache,
397→    checkpoint: &CheckpointMeta,
398→) -> HashMap<String, FileStatus> {
399→    let mut statuses = HashMap::new();
400→    for hash in &checkpoint.commit_hashes {
401→        if let Some(diffs) = cache.cached_diffs(hash) {
402→            for diff in diffs {
403→                statuses.entry(diff.path.clone()).or_insert(diff.status);
