// ---------------------------------------------------------------------------
// Key handling
// ---------------------------------------------------------------------------

/// Handle key events for the search overlay.
pub fn handle_key(key: KeyEvent, state: &mut SearchOverlayState) -> SearchOverlayAction {
    match key.code {
        KeyCode::Esc => SearchOverlayAction::Close,

        KeyCode::Enter => {
            if let Some(result) = state.results.get(state.selected) {
                SearchOverlayAction::OpenCheckpoint(result.checkpoint_idx)
            } else {
                SearchOverlayAction::None
            }
        }

        KeyCode::Tab => {
            state.scope = match state.scope {
                SearchScope::AllBranches => SearchScope::CurrentBranch,
                SearchScope::CurrentBranch => SearchScope::AllBranches,
            };
            SearchOverlayAction::ScopeChanged
        }

        KeyCode::Down | KeyCode::Char('j') if !key.modifiers.contains(KeyModifiers::CONTROL) => {
            // j without modifiers navigates; but we also need to allow typing
            // 'j' into the input. We distinguish by checking if this is a
            // navigation key (Down) or the char 'j'. Since the search overlay
            // is always in input mode, printable chars go to input. Only
            // Down/Up arrow keys navigate.
            //
            // Re-evaluate: per spec, j/k should navigate. But the spec also
            // says "all typing goes to the input". The spec lists j/k as
            // navigate keys. Let's follow the spec: Down/Ctrl-n navigate,
            // and j/k also navigate (not typed into input). Only "printable
            // chars" that are not bound to a shortcut go to input.
            state.select_next();
            SearchOverlayAction::None
        }

        KeyCode::Up | KeyCode::Char('k') if !key.modifiers.contains(KeyModifiers::CONTROL) => {
            state.select_prev();
            SearchOverlayAction::None
        }

        KeyCode::Char('n') if key.modifiers.contains(KeyModifiers::CONTROL) => {
            state.select_next();
            SearchOverlayAction::None
        }

        KeyCode::Char('p') if key.modifiers.contains(KeyModifiers::CONTROL) => {
            state.select_prev();
            SearchOverlayAction::None
        }

        KeyCode::Char('u') if key.modifiers.contains(KeyModifiers::CONTROL) => {
            state.input.clear();
            state.selected = 0;
            state.list_state.select(None);
            SearchOverlayAction::QueryChanged
        }

        KeyCode::Backspace => {
            state.input.pop();
            state.selected = 0;
            if !state.results.is_empty() {
                state.list_state.select(Some(0));
            }
            SearchOverlayAction::QueryChanged
        }

        KeyCode::Char(c) => {
            state.input.push(c);
            state.selected = 0;
            if !state.results.is_empty() {
                state.list_state.select(Some(0));
            }
            SearchOverlayAction::QueryChanged
        }

        _ => SearchOverlayAction::None,
    }
}

