                    format!(
                        " \u{2014} {} ({}){match_suffix}",
                        truncate(&result.title, max_width.saturating_sub(30)),
                        result.time_ago,
                    ),
                    Style::default().add_modifier(Modifier::BOLD),
                ),
            ]);

