            let snippet = truncate(&result.snippet, max_width.saturating_sub(10));
            let line2 = Line::from(Span::styled(
                format!("    \"{snippet}\""),
                Style::default()
                    .fg(Color::DarkGray)
                    .add_modifier(Modifier::ITALIC),
            ));

            // Blank line separator.
            let blank = Line::from("");

            ListItem::new(vec![line1, line2, blank])
        })
        .collect();

    // Suppress the unused binding warning — header_text was only used for
    // length estimation; actual rendering uses individual spans.
    let _ = &items;

    let list = List::new(items)
        .highlight_style(Style::default().bg(Color::DarkGray))
        .highlight_symbol("> ");

