                SearchOverlayAction::QueryChanged
            }
            _ => SearchOverlayAction::None,
        };
    }

    match key.code {
        KeyCode::Esc => SearchOverlayAction::Close,

        KeyCode::Enter => {
            if let Some(result) = state.results.get(state.selected) {
